    def check_rate_limit(self, identifier: str, max_requests: int = 100, 
                         window_seconds: Optional[int] = None) -> Dict[str, Any]:
        """Check and update rate limit for an identifier."""
        try:
            window = window_seconds or self.config.RATE_LIMIT_TTL
            key = self._make_key("ratelimit", f"{identifier}:{int(datetime.utcnow().timestamp()) // window}")
            
            pipeline = self.client.pipeline()
            pipeline.incr(key)
            pipeline.ttl(key)
            results = pipeline.execute()
            
            current_count = results[0]
            current_ttl = results[1]
            
            if current_ttl == -1:
                self.client.expire(key, window)
            
            allowed = current_count <= max_requests
            
            return {
                "allowed": allowed,
                "current_count": current_count,
                "max_requests": max_requests,
                "remaining": max(0, max_requests - current_count),
                "reset_in": current_ttl if current_ttl > 0 else window
            }
        except redis.RedisError as e:
            logger.error(f"Rate limit check failed: {e}")
            return {"allowed": True, "error": "rate_limit_unavailable"}
    
    def health_check(self) -> Dict[str, Any]:
        """Check Redis connection health."""
        try:
            start = datetime.utcnow()
            self.client.ping()
            latency = (datetime.utcnow() - start).total_seconds() * 1000
            
            info = self.client.info(section="server")
            
            return {
                "status": "healthy",
                "latency_ms": round(latency, 2),
                "redis_version": info.get("redis_version", "unknown"),
                "ssl": True,
                "connected_at": datetime.utcnow().isoformat()
            }
        except redis.RedisError as e:
            return {
                "status": "unhealthy",
                "error": str(e)
            }
    
    def close(self):
        """Close Redis connections."""
        if self._client:
            self._client.close()
            self._client = None
        if self._pool:
            self._pool.disconnect()
            self._pool = None
        logger.info("Redis connections closed")


