def require_auth(f):
    """Decorator to require valid session token."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get("Authorization", "")
        if not auth_header.startswith("Bearer "):
            return jsonify({"error": "Missing or invalid authorization header"}), 401
        
        token = auth_header[7:]
        user_id = redis_client.validate_session_token(token)
        
        if user_id is None:
            return jsonify({"error": "Invalid or expired session token"}), 401
        
        request.user_id = user_id
        request.session_token = token
        return f(*args, **kwargs)
    
    return decorated


@app.route("/health", methods=["GET"])
def health():
    """Health check endpoint."""
    result = redis_client.health_check()
    status_code = 200 if result["status"] == "healthy" else 503
    return jsonify(result), status_code


@app.route("/api/v1/sessions", methods=["POST"])
def create_session():
    """Create a new session for a user."""
    data = request.get_json()
    if not data or "user_id" not in data:
        return jsonify({"error": "user_id is required"}), 400
    
    user_id = data["user_id"]
    session_token = secrets.token_urlsafe(48)
    
    metadata = {
        "ip_address": request.remote_addr,
        "user_agent": request.headers.get("User-Agent", "unknown"),
    }
    
    success = redis_client.store_session_token(user_id, session_token, metadata)
    
    if success:
        return jsonify({
            "session_token": session_token,
            "expires_in": SecureRedisConfig.SESSION_TOKEN_TTL,
            "token_type": "Bearer"
        }), 201
    
    return jsonify({"error": "Failed to create session"}), 500


@app.route("/api/v1/sessions/validate", methods=["POST"])
def validate_session():
    """Validate a session token."""
    data = request.get_json()
    if not data or "token" not in data:
        return jsonify({"error": "token is required"}), 400
    
    user_id = redis_client.validate_session_token(data["token"])
    
    if user_id:
        return jsonify({"valid": True, "user_id": user_id}), 200
    
    return jsonify({"valid": False}), 401


