@require_auth
def create_api_key():
    """Create a new API key."""
    data = request.get_json() or {}
    
    api_key_id = secrets.token_urlsafe(16)
    api_secret = secrets.token_urlsafe(32)
    
    api_key_data = {
        "secret": api_secret,
        "owner": request.user_id,
        "permissions": data.get("permissions", ["read"]),
        "rate_limit": data.get("rate_limit", 1000),
    }
    
    success = redis_client.store_api_key(api_key_id, api_key_data)
    
    if success:
        return jsonify({
            "api_key_id": api_key_id,
            "api_secret": api_secret,
            "expires_in": SecureRedisConfig.API_KEY_TTL,
            "message": "Store the api_secret securely. It will not be shown again."
        }), 201
    
    return jsonify({"error": "Failed to create API key"}), 500


@app.route("/api/v1/api-keys/validate", methods=["POST"])
def validate_api_key():
    """Validate an API key."""
    data = request.get_json()
    if not data or "api_key_id" not in data or "api_secret" not in data:
        return jsonify({"error": "api_key_id and api_secret are required"}), 400
    
    rate_limit = redis_client.check_rate_limit(data["api_key_id"])
    if not rate_limit.get("allowed", True):
        return jsonify({
            "error": "Rate limit exceeded",
            "retry_after": rate_limit.get("reset_in", 60)
        }), 429
    
    result = redis_client.validate_api_key(data["api_key_id"], data["api_secret"])
    
    if result:
        return jsonify({
            "valid": True,
            "key_data": result,
            "rate_limit": rate_limit
        }), 200
    
    return jsonify({"valid": False}), 401


